query:
SET @cloud_id = (SELECT id FROM courses WHERE title = 'Cloud & DevOps Avançado' LIMIT 1);

-- Atualizar todas as aulas de Cloud com vídeos
UPDATE lessons SET video_url = 'https://www.youtube.com/embed/8KmqmKj2nQI' WHERE module_id IN (SELECT id FROM modules WHERE course_id = @cloud_id) AND title = 'Modelos de Cloud';
