UPDATE lessons SET video_url = 'https://www.youtube.com/embed/X48VuDVv0Z0' WHERE module_id IN (SELECT id FROM modules WHERE course_id = @cloud_id) AND title = 'Orquestração com Kubernetes';
UPDATE lessons SET video_url = 'https://www.youtube.com/embed/scEDHM3SPak' WHERE module_id IN (SELECT id FROM modules WHERE course_id = @cloud_id) AND title = 'CI/CD Pipelines';
UPDATE lessons SET video_url = 'https://www.youtube.com/embed/l6-r6E1iRjc' WHERE module_id IN (SELECT id FROM modules WHERE course_id = @cloud_id) AND title = 'Terraform Fundamentos';
UPDATE lessons SET video_url = 'https://www.youtube.com/embed/PJQvNjnMHD0' WHERE module_id IN (SELECT id FROM modules WHERE course_id = @cloud_id) AND title = 'CloudFormation vs Terraform';
UPDATE lessons SET video_url = 'https://www.youtube.com/embed/N-GV8F7hIts' WHERE module_id IN (SELECT id FROM modules WHERE course_id = @cloud_id) AND title = 'Monitoramento e Logging';

SELECT COUNT(*) as cloud_videos FROM lessons WHERE module_id IN (SELECT id FROM modules WHERE course_id = @cloud_id) AND video_url IS NOT NULL;

